class efuAI {
    constructor() {
        this.apiUrl = ""; // API 地址，将在 init 中设置
        this.apiKey = ""; // API 密钥，将在 init 中设置
        this.aiTalkMode = false; // AI 对话模式标志
        this.aiPostExplanation = ''; // AI 生成的解释
        this.config = GLOBAL_CONFIG.post_ai; // 配置
        this.scoGPTIsRunning = false; // AI 是否正在运行的标志
    }

    init() {
        // 从配置中读取 API 地址和密钥
        this.apiUrl = this.config.apiUrl; // 从 post_ai 中读取 apiUrl
        this.apiKey = this.config.apiKey; // 从 post_ai 中读取 apiKey

        // 检查解释元素是否存在
        if (!document.querySelector(".ai-explanation")) return;

        this.scoGPTIsRunning = false;
        this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;

        // 如果没有提供解释，则生成
        if (!this.aiPostExplanation) {
            this.generate();
        } else {
            this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
        }

        this.AIEngine();
    }

    getTitleAndContent() {
        const e = document.getElementById("article-container");
        const t = document.title;
        const n = e.getElementsByTagName("p");
        const i = e.querySelectorAll("h1, h2, h3, h4, h5");

        // 合并标题和内容，移除 URL
        return (t + " " + Array.from(i).concat(Array.from(n)).map((e) => e.innerText.replace(/https?:\/\/[^\s]+/g, "")).join(" ")).slice(0, 1000);
    }

    async generate() {
        // 显示加载动画并获取摘要
        this.aiShowAnimation(this.fetch(document.title, this.getTitleAndContent()));
    }

    async fetch(title, content) {
        const url = `${this.apiUrl}/chat/completions`;
        const body = {
            model: this.config.model, // 使用配置中的模型
            messages: [{ role: "user", content: `${title}\n${content}` }],
            max_tokens: 150 // 根据需要调整
        };

        try {
            const response = await fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${this.apiKey}`
                },
                body: JSON.stringify(body)
            });

            const data = await response.json();

            // 检查响应是否成功
            if (response.ok) {
                this.aiPostExplanation = data.choices[0].message.content; // 根据 OpenAI API 的响应格式
                return this.aiPostExplanation;
            } else {
                console.error("请求失败:", data.error.message);
                return data.error.message;
            }
        } catch (error) {
            console.error("请求异常:", error);
            return "请求异常";
        }
    }

    aiShowAnimation(promise, t = false) {
        const n = document.querySelector(".ai-explanation");
        const i = document.querySelector(".ai-tag");

        // 防止多次动画
        if (!n || this.scoGPTIsRunning) return;

        this.scoGPTIsRunning = true;
        this.cleanSuggestions();
        i.classList.add("loadingAI");
        n.style.display = "block";
        n.innerHTML = '生成中...<span class="blinking-cursor"></span>';

        let s, o, a = true, c = 0, r = true;

        const observer = new IntersectionObserver((entries) => {
            a = entries[0].isIntersecting;
            if (a) requestAnimationFrame(o);
        }, { threshold: 0 });

        promise.then((e) => {
            s = performance.now();
            o = () => {
                if (c < e.length && a) {
                    const r = performance.now();
                    const g = r - s;
                    const h = e.slice(c, c + 1);
                    const u = /[，。！、？,.!?]/.test(h);
                    const m = /[a-zA-Z0-9]/.test(h);

                    // 控制文本显示速度
                    if (g >= (u ? 100 * Math.random() + 100 : m ? 10 : 25)) {
                        n.innerText = e.slice(0, c + 1);
                        s = r;
                        c++;

                        if (c < e.length) {
                            n.innerHTML = e.slice(0, c) + '<span class="blinking-cursor"></span>';
                        } else {
                            n.innerHTML = e;
                            n.style.display = "block";
                            this.scoGPTIsRunning = false;
                            i.classList.remove("loadingAI");
                            observer.disconnect();
                            t && this.createSuggestions();
                        }
                    }
                    a && requestAnimationFrame(o);
                }
            };

            // 开始动画
            a && r && setTimeout(() => {
                requestAnimationFrame(o);
                r = false;
            }, 3000);

            observer.observe(n);
        }).catch((e) => {
            console.error("检索信息失败：", e);
            n.innerHTML = "检索信息失败";
            n.style.display = "block";
            this.scoGPTIsRunning = false;
            i.classList.remove("loadingAI");
            observer.disconnect();
        });
    }

    AIEngine() {
        const e = document.querySelector(".ai-tag");
        if (e) {
            e.addEventListener("click", () => {
                if (!this.scoGPTIsRunning) {
                    this.aiTalkMode = true;
                    this.aiShowAnimation(Promise.resolve(this.config.talk), true);
                }
            });
        }
    }

    cleanSuggestions() {
        const e = document.querySelector(".ai-suggestions");
        if (e) {
            e.innerHTML = "";
        } else {
            console.error("没有这个元素：'ai-suggestions'");
        }
    }

    createSuggestions() {
        if (this.aiTalkMode) {
            this.cleanSuggestions();
            this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
                if (this.aiPostExplanation === "") {
                    this.generate();
                } else {
                    this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
                }
            });

            if (this.config.randomPost) {
                this.createSuggestionItemWithAction("带我去看看其他文章", () => toRandomPost());
            }

            this.aiTalkMode = true;
        }
    }

    createSuggestionItemWithAction(text, action) {
        const n = document.querySelector(".ai-suggestions");
        if (!n) {
            return void console.error("无法找到具有class为ai-suggestions的元素");
        }

        const item = document.createElement("div");
        item.classList.add("ai-suggestions-item");
        item.textContent = text;
        item.addEventListener("click", action);
        n.appendChild(item);
    }
}

const efu_ai = new efuAI();